import{_ as r}from"./chunks/p-to-c-kcp-mesh.C_5kzAvo.js";import{_ as t,o,c as a,a5 as s}from"./chunks/framework.BHJU2Fgd.js";const i="/pr-preview/pr-195/diagrams/p-to-c-kcp-mesh-multiple.svg",n="/pr-preview/pr-195/diagrams/extended-export.svg",f=JSON.parse('{"title":"Provider to consumer","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/interaction-patterns/provider-to-consumer.md","filePath":"concepts/interaction-patterns/provider-to-consumer.md"}'),c={name:"concepts/interaction-patterns/provider-to-consumer.md"};function d(p,e,h,l,u,m){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="provider-to-consumer" tabindex="-1">Provider to consumer <a class="header-anchor" href="#provider-to-consumer" aria-label="Permalink to &quot;Provider to consumer&quot;">​</a></h1><p>The provider-to-consumer pattern is the default Platform Mesh relationship: a service provider exposes a service API, and a service consumer uses that API from an isolated account workspace.</p><p>Use this pattern when consumers should manage service instances through a declarative API without receiving direct access to the provider runtime.</p><h2 id="participating-personas" tabindex="-1">Participating personas <a class="header-anchor" href="#participating-personas" aria-label="Permalink to &quot;Participating personas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Persona</th><th>Role in the pattern</th></tr></thead><tbody><tr><td>Platform owner</td><td>Operates the mesh, account hierarchy, identity, authorization, and provider onboarding.</td></tr><tr><td>Service provider</td><td>Publishes the service API and reconciles consumer intent into provider-owned runtime resources.</td></tr><tr><td>Service consumer</td><td>Discovers the service, binds the API when needed, and creates desired-state resources.</td></tr></tbody></table><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><p>The provider exposes only the API surface required for the service. The consumer works with that API through Platform Mesh, usually from a consumer account workspace. Platform Mesh mediates identity, authorization, account isolation, API discovery, and the flow of desired state and status.</p><p>When the consumer uses Platform Mesh directly, the provider can expose service APIs through kcp APIExports and api-syncagent. Consumer workspaces bind those APIs with APIBindings.</p><p><img src="'+r+'" alt="Kube provider to Platform Mesh consumer diagram"></p><p>The same pattern supports multiple consumers and multiple providers.</p><p><img src="'+i+'" alt="Kube provider to Platform Mesh multiple consumers diagram"></p><p>When consumers need APIs close to their workload clusters, kube-bind can project Platform Mesh APIs into consumer-owned Kubernetes clusters.</p><p><img src="'+n+'" alt="Extended export diagram"></p><h2 id="ownership-boundaries" tabindex="-1">Ownership boundaries <a class="header-anchor" href="#ownership-boundaries" aria-label="Permalink to &quot;Ownership boundaries&quot;">​</a></h2><p>The consumer owns the requested service resources in its account workspace. The provider owns the controller logic, runtime resources, and service implementation. Platform Mesh owns the shared control-plane boundary between them.</p><p>This separation lets consumers use a consistent Kubernetes Resource Model interface while providers keep their runtime topology and operational model private.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../personas/">Personas</a></li><li><a href="./../account-model.html">Account model</a></li><li><a href="./../integration-paths.html">Integration paths</a></li><li><a href="./../api-sharing.html">API sharing</a></li></ul>',18)])])}const w=t(c,[["render",d]]);export{f as __pageData,w as default};
